                    "regex": "AKIA[0-9A-Z]{16}",
                    "issue": "Vulnerabilidade Crítica: Chave AWS exposta no código TypeScript.",
                    "severity": "critical"
          },
          {
                    "regex": "(?:api[_-]?key|apiKey|API_KEY)\\s*[:=]\\s*[\"'][^\"']{8,}",
                    "issue": "Vazamento: API Key hardcoded no código-fonte.",
                    "severity": "critical"
          },
          {
                    "regex": "(?:password|passwd|secret)\\s*[:=]\\s*[\"'][^\"']+[\"']",
                    "issue": "Vazamento: Credencial hardcoded no código-fonte.",
                    "severity": "critical"
          },
          {
                    "regex": "sk-[a-zA-Z0-9]{20,}",
                    "issue": "Vulnerabilidade Crítica: Chave OpenAI exposta.",
                    "severity": "critical"
          },
          {
